const atlas=document.getElementById("atlas"),bubbles=document.getElementById("bubbles"),barsContainer=document.getElementById("bars"),timeSlider=document.getElementById("timeSlider"),timeLabel=document.getElementById("timeLabel"),autoTimeBtn=document.getElementById("autoTime"),sendAtlasBtn=document.getElementById("sendAtlas"),clockEl=document.getElementById("clock");let autoTime=false,nextAtlasTimer=null;const stages=[{h:0,name:"Quiet Ocean",deep:"#01040b",a:"#031020",b:"#061b31",c:"#2c72aa",glow:"#66bfff",ui:.62},{h:3,name:"Deep Sleep",deep:"#01030a",a:"#06101f",b:"#0b1730",c:"#376fa0",glow:"#82c9ff",ui:.56},{h:5,name:"Dawn",deep:"#07101d",a:"#253152",b:"#6f6b99",c:"#f1b58f",glow:"#ffd7b0",ui:.8},{h:7,name:"Morning",deep:"#04111d",a:"#0a4260",b:"#1296b4",c:"#9eeeff",glow:"#d0f8ff",ui:.95},{h:10,name:"Midday",deep:"#031020",a:"#063b72",b:"#087dc7",c:"#34c8ff",glow:"#9feaff",ui:1},{h:13,name:"Afternoon",deep:"#03101d",a:"#092f5a",b:"#0a66a8",c:"#29b4df",glow:"#88dcff",ui:.96},{h:16,name:"Late Afternoon",deep:"#061221",a:"#17435d",b:"#3d718d",c:"#e0c68f",glow:"#ffe0a8",ui:.92},{h:18,name:"Golden Hour",deep:"#0b101c",a:"#3b2941",b:"#91563d",c:"#ffb454",glow:"#ffd28a",ui:.88},{h:19.5,name:"Blue Hour",deep:"#050818",a:"#171c52",b:"#3d3d80",c:"#c084b7",glow:"#aab8ff",ui:.8},{h:21,name:"Evening",deep:"#020713",a:"#071a35",b:"#0b3463",c:"#1e7eb8",glow:"#76cfff",ui:.72},{h:23,name:"Late Night",deep:"#01040c",a:"#051326",b:"#09294d",c:"#0d6ba6",glow:"#5ebeff",ui:.64},{h:24,name:"Quiet Ocean",deep:"#01040b",a:"#031020",b:"#061b31",c:"#2c72aa",glow:"#66bfff",ui:.62}];function hexToRgb(hex){const v=hex.replace("#","");return{r:parseInt(v.slice(0,2),16),g:parseInt(v.slice(2,4),16),b:parseInt(v.slice(4,6),16)}}function mixHex(a,b,t){const A=hexToRgb(a),B=hexToRgb(b),m=k=>Math.round(A[k]+(B[k]-A[k])*t).toString(16).padStart(2,"0");return`#${m("r")}${m("g")}${m("b")}`}function stageAt(hour){for(let i=0;i<stages.length-1;i++){const a=stages[i],b=stages[i+1];if(hour>=a.h&&hour<=b.h){const t=(hour-a.h)/(b.h-a.h||1);return{name:t<.5?a.name:b.name,deep:mixHex(a.deep,b.deep,t),a:mixHex(a.a,b.a,t),b:mixHex(a.b,b.b,t),c:mixHex(a.c,b.c,t),glow:mixHex(a.glow,b.glow,t),ui:a.ui+(b.ui-a.ui)*t}}}return stages[0]}function formatTime(hour){const h=Math.floor(hour)%24,minutes=Math.floor((hour-Math.floor(hour))*60),ap=h>=12?"PM":"AM",hh=((h+11)%12)+1;return`${hh}:${String(minutes).padStart(2,"0")} ${ap}`}function applyOceanTime(hour){const s=stageAt(hour),root=document.documentElement;root.style.setProperty("--deep",s.deep);root.style.setProperty("--water-a",s.a);root.style.setProperty("--water-b",s.b);root.style.setProperty("--water-c",s.c);root.style.setProperty("--glow",s.glow);root.style.setProperty("--ui-opacity",s.ui.toFixed(2));timeLabel.textContent=`${formatTime(hour)} · ${s.name}`;clockEl.textContent=formatTime(hour)}for(let i=0;i<28;i++){const bar=document.createElement("div");bar.className="bar";bar.style.height=`${18+Math.random()*62}%`;barsContainer.appendChild(bar)}function animateBars(){[...barsContainer.children].forEach((bar,i)=>{const wave=34+28*Math.sin(Date.now()/560+i*.58),noise=Math.random()*25;bar.style.height=`${Math.max(8,Math.min(98,wave+noise))}%`});setTimeout(animateBars,170)}function spawnBubble(){const bubble=document.createElement("div");bubble.className="bubble";const size=4+Math.random()*20;bubble.style.width=`${size}px`;bubble.style.height=`${size}px`;bubble.style.left=`${3+Math.random()*94}%`;bubble.style.setProperty("--drift",`${-45+Math.random()*90}px`);bubble.style.animationDuration=`${10+Math.random()*18}s`;bubbles.appendChild(bubble);bubble.addEventListener("animationend",()=>bubble.remove())}setInterval(()=>{const count=Math.random()<.25?2:1;for(let i=0;i<count;i++)setTimeout(spawnBubble,i*260)},1050);function sendAtlas(){atlas.classList.remove("swimming");atlas.style.top=`${29+Math.random()*26}%`;atlas.style.setProperty("--crossing",`${31+Math.random()*14}s`);void atlas.offsetWidth;atlas.classList.add("swimming")}function scheduleAtlas(){clearTimeout(nextAtlasTimer);nextAtlasTimer=setTimeout(()=>{sendAtlas();scheduleAtlas()},45000+Math.random()*70000)}atlas.addEventListener("animationend",()=>atlas.classList.remove("swimming"));timeSlider.addEventListener("input",()=>{autoTime=false;applyOceanTime(Number(timeSlider.value))});autoTimeBtn.addEventListener("click",()=>{autoTime=true;updateFromClock()});sendAtlasBtn.addEventListener("click",sendAtlas);function updateFromClock(){if(!autoTime)return;const d=new Date(),hour=d.getHours()+d.getMinutes()/60+d.getSeconds()/3600;timeSlider.value=hour;applyOceanTime(hour)}animateBars();applyOceanTime(Number(timeSlider.value));setTimeout(sendAtlas,1800);scheduleAtlas();setInterval(updateFromClock,1000);